import java.util.ArrayList;import java.util.List;import java.util.Map;
final class ChainOfResponsibilityPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}interface Handler{String handle(Map<String,Object>request,List<String>visited);}abstract static class LinkedHandler implements Handler{final Handler next;LinkedHandler(Handler n){next=n;}}
static final class Auth extends LinkedHandler{Auth(Handler n){super(n);}public String handle(Map<String,Object>r,List<String>v){v.add("auth");if(!"valid".equals(r.get("token")))throw new PatternException("unauthenticated");return next.handle(r,v);}}static final class Quota extends LinkedHandler{Quota(Handler n){super(n);}public String handle(Map<String,Object>r,List<String>v){v.add("quota");if(((Number)r.getOrDefault("quota",0)).intValue()<=0)throw new PatternException("quota_exhausted");return next.handle(r,v);}}static final class Execute implements Handler{public String handle(Map<String,Object>r,List<String>v){v.add("execute");return"accepted:"+r.get("payload");}}
@SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Handler chain=new Auth(new Quota(new Execute()));List<Map<String,Object>>out=new ArrayList<>();for(Map<String,Object>r:(List<Map<String,Object>>)input.getOrDefault("requests",List.of())){List<String>visited=new ArrayList<>();out.add(Map.of("decision",chain.handle(r,visited),"visited",visited));}return Map.of("responses",out);}}
